+
+function stripFormatting(text: string): string {
+  return text
+    .replace(/`([^`]*)`/g, '$1')
+    .replace(/(\\*\\*\\*|___)(.*?)\\1/g, '$2')
+    .replace(/(\\*\\*|__)(.*?)\\1/g, '$2')
+    .replace(/(\\*|_)(.*?)\\1/g, '$2')
